747	  wall: WallElem,
748	  elevM: number,
749	  hostedDoors: DoorElem[],
750	  hostedWindows: WindowElem[],
751	  paint: ViewportPaintBundle | null,
752	  evaluator: Evaluator,
753	): THREE.Mesh {
754	  const sx  = wall.start.xMm / 1000;
755	  const sz  = wall.start.yMm / 1000;
756	  const dx  = wall.end.xMm / 1000 - sx;
757	  const dz  = wall.end.yMm / 1000 - sz;
758	  const len = Math.max(0.001, Math.hypot(dx, dz));
759	  const height = THREE.MathUtils.clamp(wall.heightMm / 1000, 0.25, 40);
760	  const thick  = THREE.MathUtils.clamp(wall.thicknessMm / 1000, 0.05, 2);
761	  const yaw    = Math.atan2(dz, dx);
762	  const wcx    = sx + dx / 2;
763	  const wcz    = sz + dz / 2;
764	  const wcy    = elevM + height / 2;
765	
766	  const wallMat = new THREE.MeshStandardMaterial({
767	    color: categoryColorOr(paint, 'wall'),
768	    roughness: paint?.categories.wall.roughness ?? 0.85,
769	    metalness: paint?.categories.wall.metalness ?? 0.0,
770	  });
771	
772	  try {
773	    // Wall brush at identity — geometry centred on (0,0,0) in wall-local space.
774	    let wallBrush = new Brush(new THREE.BoxGeometry(len, height, thick), wallMat);
775	    wallBrush.updateMatrixWorld();
776	
777	    for (const door of hostedDoors) {
778	      // Cutter spans full door height from floor; add tolerance so the cut goes
779	      // cleanly through the wall face (+0.04 wide, +0.01 tall, +0.1 deep).
780	      const leafH  = THREE.MathUtils.clamp((wall.heightMm / 1000) * 0.86, 0.6, 2.5);
781	      const cutW   = THREE.MathUtils.clamp(door.widthMm / 1000, 0.35, 4) + 0.04;
782	      const cutH   = Math.min(leafH + 0.01, height - 0.01);
783	      const cutD   = thick + 0.1;
784	      // localX: (alongT=0.5) → 0; (alongT=0) → −len/2; (alongT=1) → +len/2
785	      const localX = (door.alongT - 0.5) * len;
786	      // localY: bottom of cutter sits on floor (world y=elevM = local y=−height/2)
787	      const localY = cutH / 2 - height / 2;
788	
789	      const cutter = new Brush(new THREE.BoxGeometry(cutW, cutH, cutD));
790	      cutter.position.set(localX, localY, 0);
791	      cutter.updateMatrixWorld();
792	      wallBrush = evaluator.evaluate(wallBrush, cutter, SUBTRACTION);
793	      wallBrush.updateMatrixWorld();
794	    }
795	
796	    for (const win of hostedWindows) {
797	      const sill   = THREE.MathUtils.clamp(win.sillHeightMm / 1000, 0.06, wall.heightMm / 1000 - 0.08);
798	      const outerH = THREE.MathUtils.clamp(win.heightMm / 1000, 0.05, wall.heightMm / 1000 - sill - 0.06);
799	      const outerW = THREE.MathUtils.clamp(win.widthMm / 1000, 0.14, 4);
800	      const cutW   = outerW + 0.04;
801	      const cutH   = outerH + 0.02;
802	      const cutD   = thick + 0.1;
803	      const localX = (win.alongT - 0.5) * len;
804	      // localY: sill is from floor (local −height/2), cutter centre = sill + cutH/2 − height/2
805	      const localY = sill + cutH / 2 - height / 2;
806	
807	      const cutter = new Brush(new THREE.BoxGeometry(cutW, cutH, cutD));
808	      cutter.position.set(localX, localY, 0);
809	      cutter.updateMatrixWorld();
810	      wallBrush = evaluator.evaluate(wallBrush, cutter, SUBTRACTION);
811	      wallBrush.updateMatrixWorld();
812	    }
813	
814	    const mesh = new THREE.Mesh(wallBrush.geometry, wallMat);
815	    mesh.position.set(wcx, wcy, wcz);
816	    mesh.rotation.y = yaw;
817	    mesh.userData.bimPickId = wall.id;
818	    addEdges(mesh);
819	    return mesh;
820	  } catch {
821	    // CSG failed (e.g. degenerate geometry) — fall back to solid wall.
822	    return makeWallMesh(wall, elevM, paint);
823	  }
824	}
